--
-- Name: fleet_vehicle_odometer_report; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.fleet_vehicle_odometer_report AS
 WITH vehicle_odometer AS (
         SELECT vehicle.id AS vehicle_id,
            odometer.value,
            (odometer.date)::timestamp without time zone AS date,
            (vehicle.acquisition_date)::timestamp without time zone AS acquisition_date
           FROM (public.fleet_vehicle_odometer odometer
             LEFT JOIN public.fleet_vehicle vehicle ON ((vehicle.id = odometer.vehicle_id)))
        ), vehicle_odometer_single_date AS (
         SELECT DISTINCT ON (t_1.vehicle_id, t_1.date) t_1.vehicle_id,
            t_1.date,
            t_1.value,
            t_1.acquisition_date
           FROM (vehicle_odometer t_1
             JOIN ( SELECT vehicle_odometer.vehicle_id,
                    vehicle_odometer.date,
                    max(vehicle_odometer.value) AS max_value
                   FROM vehicle_odometer
                  GROUP BY vehicle_odometer.vehicle_id, vehicle_odometer.date) t_max_val ON (((t_1.vehicle_id = t_max_val.vehicle_id) AND (t_1.date = t_max_val.date) AND (t_1.value = t_max_val.max_value))))
        ), vehicle_odometer_acquisition_date AS (
         SELECT vehicle_odometer_single_date.vehicle_id,
            vehicle_odometer_single_date.date,
            vehicle_odometer_single_date.value,
            vehicle_odometer_single_date.acquisition_date
           FROM vehicle_odometer_single_date
        UNION ALL
         SELECT vehicle_odometer_single_date.vehicle_id,
            vehicle_odometer_single_date.acquisition_date AS date,
            0 AS value,
            vehicle_odometer_single_date.acquisition_date
           FROM vehicle_odometer_single_date
          GROUP BY vehicle_odometer_single_date.vehicle_id, vehicle_odometer_single_date.acquisition_date
         HAVING (vehicle_odometer_single_date.acquisition_date < min(vehicle_odometer_single_date.date))
        ), vehicle_odometer_prev_and_next AS (
         SELECT vehicle_odometer_acquisition_date.vehicle_id,
            vehicle_odometer_acquisition_date.date,
            vehicle_odometer_acquisition_date.value,
            vehicle_odometer_acquisition_date.acquisition_date,
            lag(vehicle_odometer_acquisition_date.date) OVER (PARTITION BY vehicle_odometer_acquisition_date.vehicle_id ORDER BY vehicle_odometer_acquisition_date.date) AS prev_date,
            lag(vehicle_odometer_acquisition_date.value) OVER (PARTITION BY vehicle_odometer_acquisition_date.vehicle_id ORDER BY vehicle_odometer_acquisition_date.date) AS prev_val,
            lead(vehicle_odometer_acquisition_date.date) OVER (PARTITION BY vehicle_odometer_acquisition_date.vehicle_id ORDER BY vehicle_odometer_acquisition_date.date) AS next_date,
            lead(vehicle_odometer_acquisition_date.value) OVER (PARTITION BY vehicle_odometer_acquisition_date.vehicle_id ORDER BY vehicle_odometer_acquisition_date.date) AS next_val
           FROM vehicle_odometer_acquisition_date
        ), vehicle_odometer_date_range AS (
         SELECT vehicle_odometer_prev_and_next.vehicle_id,
            COALESCE(date_trunc('month'::text, min(vehicle_odometer_prev_and_next.acquisition_date)), date_trunc('month'::text, min(vehicle_odometer_prev_and_next.date))) AS start_date,
            date_trunc('month'::text, max(vehicle_odometer_prev_and_next.date)) AS end_date
           FROM vehicle_odometer_prev_and_next
          GROUP BY vehicle_odometer_prev_and_next.vehicle_id
        ), vehicle_odometer_date_range_min_date AS (
         SELECT date_range.vehicle_id,
            COALESCE(odometer.date, generated_months.date) AS date,
            COALESCE(odometer.value, (0)::double precision) AS value,
            first_value(COALESCE(odometer.date, generated_months.date)) OVER (PARTITION BY date_range.vehicle_id ORDER BY generated_months.date) AS min_date,
            odometer.prev_date,
            odometer.prev_val,
            odometer.next_date,
            odometer.next_val
           FROM ((vehicle_odometer_date_range date_range
             CROSS JOIN LATERAL generate_series(date_range.start_date, date_range.end_date, '1 mon'::interval) generated_months(date))
             LEFT JOIN vehicle_odometer_prev_and_next odometer ON (((date_range.vehicle_id = odometer.vehicle_id) AND (generated_months.date = date_trunc('month'::text, odometer.date)))))
        ), vehicle_odometer_prev_next_date AS (
         SELECT odometer.vehicle_id,
            odometer.date,
            max(COALESCE(odometer.prev_date, odo_prev_next.prev_date)) AS prev_date,
            min(COALESCE(odometer.next_date, odo_prev_next.next_date)) AS next_date
           FROM (vehicle_odometer_date_range_min_date odometer
             LEFT JOIN vehicle_odometer_prev_and_next odo_prev_next ON (((odometer.vehicle_id = odo_prev_next.vehicle_id) AND ((odo_prev_next.prev_date IS NULL) OR (odo_prev_next.prev_date < odometer.date)) AND ((odo_prev_next.next_date IS NULL) OR (odo_prev_next.next_date > odometer.date)))))
          GROUP BY odometer.vehicle_id, odometer.date
        ), vehicle_odometer_prev_next_complete AS (
         SELECT DISTINCT odo_dates.vehicle_id,
            odo_dates.date,
            odometer.min_date,
            odometer.value,
            odo_dates.prev_date,
            odometer_prev.value AS prev_value,
            odo_dates.next_date,
            odometer_next.value AS next_value
           FROM (((vehicle_odometer_prev_next_date odo_dates
             LEFT JOIN vehicle_odometer_date_range_min_date odometer ON (((odo_dates.vehicle_id = odometer.vehicle_id) AND (odo_dates.date = odometer.date))))
             LEFT JOIN vehicle_odometer_date_range_min_date odometer_prev ON (((odo_dates.vehicle_id = odometer_prev.vehicle_id) AND (odo_dates.prev_date = odometer_prev.date))))
             LEFT JOIN vehicle_odometer_date_range_min_date odometer_next ON (((odo_dates.vehicle_id = odometer_next.vehicle_id) AND (odo_dates.next_date = odometer_next.date))))
        ), vehicle_odometer_strict_prev AS (
         SELECT vehicle_odometer_prev_next_complete.vehicle_id,
            vehicle_odometer_prev_next_complete.date,
            vehicle_odometer_prev_next_complete.min_date,
            vehicle_odometer_prev_next_complete.value,
            vehicle_odometer_prev_next_complete.prev_date,
            vehicle_odometer_prev_next_complete.prev_value,
            vehicle_odometer_prev_next_complete.next_date,
            vehicle_odometer_prev_next_complete.next_value,
            lag(vehicle_odometer_prev_next_complete.date) OVER (PARTITION BY vehicle_odometer_prev_next_complete.vehicle_id ORDER BY vehicle_odometer_prev_next_complete.date) AS strict_previous_date
           FROM vehicle_odometer_prev_next_complete
        ), vehicle_odometer_filled_gaps AS (
         SELECT vehicle_odometer_strict_prev.vehicle_id,
            vehicle_odometer_strict_prev.date,
            vehicle_odometer_strict_prev.value,
                CASE
                    WHEN ((vehicle_odometer_strict_prev.value = (0)::double precision) AND (vehicle_odometer_strict_prev.prev_value IS NOT NULL) AND (vehicle_odometer_strict_prev.next_value IS NOT NULL)) THEN ((vehicle_odometer_strict_prev.next_value - vehicle_odometer_strict_prev.prev_value) * ((EXTRACT(day FROM (vehicle_odometer_strict_prev.date - vehicle_odometer_strict_prev.strict_previous_date)) / NULLIF(EXTRACT(day FROM (vehicle_odometer_strict_prev.next_date - vehicle_odometer_strict_prev.prev_date)), (0)::numeric)))::double precision)
                    WHEN (vehicle_odometer_strict_prev.prev_value IS NULL) THEN vehicle_odometer_strict_prev.value
                    ELSE ((vehicle_odometer_strict_prev.value - vehicle_odometer_strict_prev.prev_value) * ((EXTRACT(day FROM (vehicle_odometer_strict_prev.date - vehicle_odometer_strict_prev.strict_previous_date)) / NULLIF(EXTRACT(day FROM (vehicle_odometer_strict_prev.date - vehicle_odometer_strict_prev.prev_date)), (0)::numeric)))::double precision)
                END AS raw_mileage_delta
           FROM vehicle_odometer_strict_prev
        ), vehicle_odometer_interpolated AS (
         SELECT vehicle_odometer_filled_gaps.vehicle_id,
            vehicle_odometer_filled_gaps.date,
                CASE
                    WHEN ((vehicle_odometer_filled_gaps.value = (0)::double precision) AND (vehicle_odometer_filled_gaps.raw_mileage_delta IS NOT NULL)) THEN sum(vehicle_odometer_filled_gaps.raw_mileage_delta) OVER (PARTITION BY vehicle_odometer_filled_gaps.vehicle_id ORDER BY vehicle_odometer_filled_gaps.date)
                    ELSE vehicle_odometer_filled_gaps.value
                END AS value
           FROM vehicle_odometer_filled_gaps
        ), vehicle_odometer_days_diff AS (
         SELECT vehicle_odometer_interpolated.vehicle_id,
            vehicle_odometer_interpolated.date,
            vehicle_odometer_interpolated.value,
            (vehicle_odometer_interpolated.value - COALESCE(lag(vehicle_odometer_interpolated.value) OVER (PARTITION BY vehicle_odometer_interpolated.vehicle_id ORDER BY vehicle_odometer_interpolated.date), (0)::double precision)) AS raw_mileage_delta,
            lag(vehicle_odometer_interpolated.date) OVER (PARTITION BY vehicle_odometer_interpolated.vehicle_id ORDER BY vehicle_odometer_interpolated.date) AS prev_date,
            EXTRACT(day FROM (vehicle_odometer_interpolated.date - lag(vehicle_odometer_interpolated.date) OVER (PARTITION BY vehicle_odometer_interpolated.vehicle_id ORDER BY vehicle_odometer_interpolated.date))) AS days_span
           FROM vehicle_odometer_interpolated
        ), vehicle_weighted_mileage AS (
         SELECT vehicle_odometer_days_diff.vehicle_id,
            vehicle_odometer_days_diff.date,
            vehicle_odometer_days_diff.value,
            vehicle_odometer_days_diff.raw_mileage_delta,
            vehicle_odometer_days_diff.prev_date,
            vehicle_odometer_days_diff.days_span,
            date_trunc('month'::text, vehicle_odometer_days_diff.prev_date) AS prev_month,
            date_trunc('month'::text, vehicle_odometer_days_diff.date) AS current_month,
                CASE
                    WHEN (to_char(vehicle_odometer_days_diff.prev_date, 'YYYY-MM'::text) = to_char(vehicle_odometer_days_diff.date, 'YYYY-MM'::text)) THEN vehicle_odometer_days_diff.raw_mileage_delta
                    ELSE (vehicle_odometer_days_diff.raw_mileage_delta * (COALESCE((EXTRACT(day FROM (vehicle_odometer_days_diff.date - date_trunc('month'::text, vehicle_odometer_days_diff.date))) / NULLIF(vehicle_odometer_days_diff.days_span, (0)::numeric)), (1)::numeric))::double precision)
                END AS current_month_mileage,
                CASE
                    WHEN (to_char(vehicle_odometer_days_diff.prev_date, 'YYYY-MM'::text) = to_char(vehicle_odometer_days_diff.date, 'YYYY-MM'::text)) THEN (0)::double precision
                    ELSE (vehicle_odometer_days_diff.raw_mileage_delta * ((EXTRACT(day FROM (date_trunc('month'::text, vehicle_odometer_days_diff.date) - vehicle_odometer_days_diff.prev_date)) / NULLIF(vehicle_odometer_days_diff.days_span, (0)::numeric)))::double precision)
                END AS prev_month_mileage
           FROM vehicle_odometer_days_diff
        ), final_results AS (
         SELECT t_1.vehicle_id,
            t_1.date AS recorded_date,
            sum(t_1.mileage_delta) OVER (PARTITION BY t_1.vehicle_id ORDER BY t_1.date) AS odometer_value,
            t_1.mileage_delta
           FROM ( SELECT t_2.vehicle_id,
                    t_2.date,
                    sum(t_2.mileage_delta) AS mileage_delta
                   FROM ( SELECT vehicle_weighted_mileage.vehicle_id,
                            vehicle_weighted_mileage.prev_month AS date,
                            vehicle_weighted_mileage.prev_month_mileage AS mileage_delta
                           FROM vehicle_weighted_mileage
                          WHERE (vehicle_weighted_mileage.prev_month IS NOT NULL)
                        UNION ALL
                         SELECT vehicle_weighted_mileage.vehicle_id,
                            vehicle_weighted_mileage.current_month AS date,
                            vehicle_weighted_mileage.current_month_mileage AS mileage_delta
                           FROM vehicle_weighted_mileage) t_2
                  GROUP BY t_2.vehicle_id, t_2.date) t_1
        ), min_month AS (
         SELECT final_results.vehicle_id,
            min(final_results.recorded_date) AS min_month_minus_one
           FROM final_results
          GROUP BY final_results.vehicle_id
        )
 SELECT row_number() OVER () AS id,
    t.vehicle_id,
    t.recorded_date,
    t.odometer_value,
    t.mileage_delta
   FROM ( SELECT min_month.vehicle_id,
            min_month.min_month_minus_one AS recorded_date,
            0 AS odometer_value,
            0 AS mileage_delta
           FROM min_month
        UNION ALL
         SELECT final_results.vehicle_id,
            (final_results.recorded_date + '1 mon'::interval) AS recorded_date,
            final_results.odometer_value,
            final_results.mileage_delta
           FROM final_results
  ORDER BY 1, 2) t;


