--
-- Name: timesheets_analysis_report; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.timesheets_analysis_report AS
 SELECT a.id,
    a.name,
    a.user_id,
    a.project_id,
    a.task_id,
    a.parent_task_id,
    a.employee_id,
    a.manager_id,
    a.company_id,
    a.department_id,
    a.currency_id,
    a.date,
    a.amount,
    a.unit_amount,
    a.partner_id,
    a.order_id,
    a.so_line,
    a.timesheet_invoice_type,
    a.timesheet_invoice_id,
    a.timesheet_revenues,
    a.billable_time,
    (a.timesheet_revenues + (a.amount)::double precision) AS margin,
    (a.unit_amount - a.billable_time) AS non_billable_time
   FROM ( SELECT a_1.id,
            a_1.name,
            a_1.user_id,
            a_1.project_id,
            a_1.task_id,
            a_1.parent_task_id,
            a_1.employee_id,
            a_1.manager_id,
            a_1.company_id,
            a_1.department_id,
            a_1.currency_id,
            a_1.date,
            a_1.amount,
            a_1.unit_amount,
            a_1.partner_id,
            a_1.order_id,
            a_1.so_line,
            a_1.timesheet_invoice_type,
            a_1.timesheet_invoice_id,
                CASE
                    WHEN ((a_1.order_id IS NULL) OR ((t.service_type)::text = ANY ((ARRAY['manual'::character varying, 'milestones'::character varying])::text[]))) THEN (0)::double precision
                    WHEN ((t.invoice_policy)::text = 'order'::text) THEN (((a_1.unit_amount * ((sol.price_subtotal / NULLIF(sol.product_uom_qty, (0)::numeric)))::double precision) / (sol_product_uom.factor)::double precision) * (a_product_uom.factor)::double precision)
                    ELSE (((a_1.unit_amount * (sol.price_unit)::double precision) / (sol_product_uom.factor)::double precision) * (a_product_uom.factor)::double precision)
                END AS timesheet_revenues,
                CASE
                    WHEN (a_1.order_id IS NULL) THEN (0)::double precision
                    ELSE a_1.unit_amount
                END AS billable_time
           FROM (((((public.account_analytic_line a_1
             LEFT JOIN public.sale_order_line sol ON ((a_1.so_line = sol.id)))
             LEFT JOIN public.uom_uom sol_product_uom ON ((sol_product_uom.id = sol.product_uom_id)))
             JOIN public.uom_uom a_product_uom ON ((a_product_uom.id = a_1.product_uom_id)))
             LEFT JOIN public.product_product p ON ((p.id = sol.product_id)))
             LEFT JOIN public.product_template t ON ((t.id = p.product_tmpl_id)))
          WHERE (a_1.project_id IS NOT NULL)) a;


