--
-- Name: fleet_vehicle_cost_report _RETURN; Type: RULE; Schema: public; Owner: -
--

CREATE OR REPLACE VIEW public.fleet_vehicle_cost_report AS
 WITH service_costs AS (
         SELECT ve.id AS vehicle_id,
            ve.company_id,
            ve.name,
            ve.driver_id,
            ve.fuel_type,
            date(date_trunc('month'::text, d.d)) AS date_start,
            vem.vehicle_type,
            COALESCE(sum(se.amount), (0)::numeric) AS cost,
            'service'::text AS cost_type
           FROM (((public.fleet_vehicle ve
             JOIN public.fleet_vehicle_model vem ON ((vem.id = ve.model_id)))
             CROSS JOIN generate_series((( SELECT min(fleet_vehicle_log_services.date) AS min
                   FROM public.fleet_vehicle_log_services))::timestamp without time zone, (CURRENT_DATE + '1 mon'::interval), '1 mon'::interval) d(d))
             LEFT JOIN public.fleet_vehicle_log_services se ON (((se.vehicle_id = ve.id) AND (date_trunc('month'::text, (se.date)::timestamp with time zone) = date_trunc('month'::text, d.d)))))
          WHERE (ve.active AND se.active AND ((se.state)::text <> 'cancelled'::text))
          GROUP BY ve.id, ve.company_id, vem.vehicle_type, ve.name, (date(date_trunc('month'::text, d.d))), d.d
          ORDER BY ve.id, (date(date_trunc('month'::text, d.d)))
        ), contract_costs AS (
         SELECT ve.id AS vehicle_id,
            ve.company_id,
            ve.name,
            ve.driver_id,
            ve.fuel_type,
            date(date_trunc('month'::text, d.d)) AS date_start,
            vem.vehicle_type,
            (((COALESCE(sum(co.amount), (0)::numeric) + COALESCE(sum((cod.cost_generated * EXTRACT(day FROM (LEAST((date_trunc('month'::text, d.d) + '1 mon'::interval), (cod.expiration_date)::timestamp without time zone) - GREATEST(date_trunc('month'::text, d.d), (cod.start_date)::timestamp without time zone))))), (0)::numeric)) + COALESCE(sum(com.cost_generated), (0)::numeric)) + COALESCE(sum(coy.cost_generated), (0)::numeric)) AS cost,
            'contract'::text AS cost_type
           FROM ((((((public.fleet_vehicle ve
             JOIN public.fleet_vehicle_model vem ON ((vem.id = ve.model_id)))
             CROSS JOIN generate_series((( SELECT min(fleet_vehicle.acquisition_date) AS min
                   FROM public.fleet_vehicle))::timestamp without time zone, (CURRENT_DATE + '1 mon'::interval), '1 mon'::interval) d(d))
             LEFT JOIN public.fleet_vehicle_log_contract co ON (((co.vehicle_id = ve.id) AND (date_trunc('month'::text, (co.date)::timestamp with time zone) = date_trunc('month'::text, d.d)))))
             LEFT JOIN public.fleet_vehicle_log_contract cod ON (((cod.vehicle_id = ve.id) AND (date_trunc('month'::text, (cod.start_date)::timestamp with time zone) <= date_trunc('month'::text, d.d)) AND (date_trunc('month'::text, (cod.expiration_date)::timestamp with time zone) >= date_trunc('month'::text, d.d)) AND ((cod.cost_frequency)::text = 'daily'::text))))
             LEFT JOIN public.fleet_vehicle_log_contract com ON (((com.vehicle_id = ve.id) AND (date_trunc('month'::text, (com.start_date)::timestamp with time zone) <= date_trunc('month'::text, d.d)) AND (date_trunc('month'::text, (com.expiration_date)::timestamp with time zone) >= date_trunc('month'::text, d.d)) AND ((com.cost_frequency)::text = 'monthly'::text))))
             LEFT JOIN public.fleet_vehicle_log_contract coy ON (((coy.vehicle_id = ve.id) AND ((d.d >= coy.start_date) AND (d.d <= coy.expiration_date)) AND (date_part('month'::text, coy.date) = date_part('month'::text, d.d)) AND ((coy.cost_frequency)::text = 'yearly'::text))))
          WHERE ve.active
          GROUP BY ve.id, ve.company_id, vem.vehicle_type, ve.name, (date(date_trunc('month'::text, d.d))), d.d
          ORDER BY ve.id, (date(date_trunc('month'::text, d.d)))
        )
 SELECT row_number() OVER (ORDER BY c.vehicle_id) AS id,
    c.company_id,
    c.vehicle_id,
    c.name,
    c.driver_id,
    c.fuel_type,
    c.date_start,
    c.vehicle_type,
    c.cost,
    c.cost_type
   FROM ( SELECT sc.company_id,
            sc.vehicle_id,
            sc.name,
            sc.driver_id,
            sc.fuel_type,
            sc.date_start,
            sc.vehicle_type,
            sc.cost,
            'service'::text AS cost_type
           FROM service_costs sc
        UNION ALL
         SELECT cc.company_id,
            cc.vehicle_id,
            cc.name,
            cc.driver_id,
            cc.fuel_type,
            cc.date_start,
            cc.vehicle_type,
            cc.cost,
            'contract'::text AS cost_type
           FROM contract_costs cc) c;


--
-- Name: report_project_task_user _RETURN; Type: RULE; Schema: public; Owner: -
--

CREATE OR REPLACE VIEW public.report_project_task_user AS
 SELECT ( SELECT 1) AS nbr,
    t.id,
    t.id AS task_id,
    t.create_date,
    t.date_assign,
    t.date_end,
    t.date_last_stage_update,
    t.date_deadline,
    t.display_in_project,
    t.project_id,
    t.priority,
    t.name,
    t.company_id,
    t.partner_id,
    t.parent_id,
    t.stage_id,
    t.state,
    t.milestone_id,
        CASE
            WHEN ((t.state)::text = ANY ((ARRAY['1_done'::character varying, '1_canceled'::character varying])::text[])) THEN true
            ELSE false
        END AS is_closed,
        CASE
            WHEN (pm.id IS NOT NULL) THEN true
            ELSE false
        END AS has_late_and_unreached_milestone,
    t.description,
    NULLIF(t.rating_last_value, (0)::double precision) AS rating_last_value,
    avg(rt.rating) AS rating_avg,
    NULLIF(t.working_days_close, (0)::double precision) AS working_days_close,
    NULLIF(t.working_days_open, (0)::double precision) AS working_days_open,
    NULLIF(t.working_hours_open, (0)::numeric) AS working_hours_open,
    NULLIF(t.working_hours_close, (0)::numeric) AS working_hours_close,
    (EXTRACT(epoch FROM (t.date_deadline - (now() AT TIME ZONE 'UTC'::text))) / ((3600 * 24))::numeric) AS delay_endings_days,
    count(td.task_id) AS dependent_ids_count,
    t.is_template,
    t.has_template_ancestor,
    t.sale_line_id,
    t.sale_order_id,
        CASE
            WHEN (COALESCE(t.allocated_hours, (0)::double precision) = (0)::double precision) THEN NULL::double precision
            ELSE ((t.effective_hours * (100)::double precision) / t.allocated_hours)
        END AS progress,
    NULLIF(t.effective_hours, (0)::double precision) AS effective_hours,
        CASE
            WHEN (COALESCE(t.allocated_hours, (0)::double precision) = (0)::double precision) THEN NULL::double precision
            ELSE (t.allocated_hours - t.effective_hours)
        END AS remaining_hours,
        CASE
            WHEN (t.allocated_hours > (0)::double precision) THEN (t.remaining_hours / t.allocated_hours)
            ELSE (0)::double precision
        END AS remaining_hours_percentage,
    NULLIF(t.allocated_hours, (0)::double precision) AS allocated_hours,
    NULLIF(t.overtime, (0)::double precision) AS overtime,
    sol.remaining_hours AS remaining_hours_so
   FROM (((((public.project_task t
     LEFT JOIN public.rating_rating rt ON (((rt.res_id = t.id) AND ((rt.res_model)::text = 'project.task'::text) AND (rt.consumed = true) AND (rt.rating >= (1)::double precision))))
     LEFT JOIN public.project_milestone pm ON (((pm.id = t.milestone_id) AND (pm.is_reached = false) AND (pm.deadline <= (now())::date))))
     LEFT JOIN public.task_dependencies_rel td ON ((td.depends_on_id = t.id)))
     LEFT JOIN public.project_project p ON ((p.id = t.project_id)))
     LEFT JOIN public.sale_order_line sol ON ((t.sale_line_id = sol.id)))
  WHERE (t.project_id IS NOT NULL)
  GROUP BY t.id, t.create_date, t.date_assign, t.date_end, t.date_last_stage_update, t.date_deadline, t.project_id, t.priority, t.name, t.company_id, t.partner_id, t.parent_id, t.stage_id, t.state, t.rating_last_value, t.working_days_close, t.working_days_open, t.working_hours_open, t.working_hours_close, t.milestone_id, pm.id, td.depends_on_id, t.sale_line_id, t.sale_order_id, t.effective_hours, t.allocated_hours, t.overtime, sol.remaining_hours;


--
-- Name: vendor_delay_report _RETURN; Type: RULE; Schema: public; Owner: -
--

CREATE OR REPLACE VIEW public.vendor_delay_report AS
 SELECT pol.id,
    min(m.date) AS date,
    pol.id AS purchase_line_id,
    pol.product_id,
    min(pc.id) AS category_id,
    pol.partner_id,
    pol.product_uom_qty AS qty_total,
    sum(
        CASE
            WHEN (((m.state)::text = 'done'::text) AND ((pol.date_planned)::date >= (m.date)::date)) THEN ((ml.quantity * ml_uom.factor) / pt_uom.factor)
            ELSE (0)::numeric
        END) AS qty_on_time
   FROM (((((((public.stock_move m
     JOIN public.purchase_order_line pol ON ((pol.id = m.purchase_line_id)))
     JOIN public.product_product p ON ((p.id = m.product_id)))
     JOIN public.product_template pt ON ((pt.id = p.product_tmpl_id)))
     JOIN public.uom_uom pt_uom ON ((pt_uom.id = pt.uom_id)))
     LEFT JOIN public.product_category pc ON ((pc.id = pt.categ_id)))
     LEFT JOIN public.stock_move_line ml ON ((ml.move_id = m.id)))
     LEFT JOIN public.uom_uom ml_uom ON ((ml_uom.id = ml.product_uom_id)))
  GROUP BY pol.id;


